function uf_upload_form() {
    if (is_user_logged_in()) {
        ?>
        <form action="" method="post" enctype="multipart/form-data">
            <label for="profile_picture">Profile Picture (jpg, png, gif):</label>
            <input type="file" name="profile_picture" id="profile_picture" accept=".jpg,.jpeg,.png,.gif"><br>
            <label for="document">Document (pdf, doc, docx):</label>
